Here's a C++ program that reads a text file line by line, counts the occurrences of a specified word, and displays the results:

**Word Counter Program: `word_counter.cpp`**
```cpp
#include <iostream>
#include <fstream>
#include <sstream>
#include <string>
using namespace std;

// Function to count word occurrences
int countWordOccurrences(const string& fileName, const string& targetWord) {
    int occurrences = 0;
    string line, word;

    ifstream file(fileName);
    if (!file.is_open()) {
        cerr << "Error opening file: " << fileName << endl;
        return -1; // Return error code if file couldn't be opened
    }

    while (getline(file, line)) {
        stringstream lineStream(line);
        while (getline(lineStream, word, ' ')) { // Split by spaces
            if (word == targetWord) { // Ignore case sensitivity (optional)
                word = boost::to_lower_copy(word); // Use Boost's to_lower_copy if needed
                if (word == boost::to_lower_copy(targetWord))
                    occurrences++; // Increment count if words match
            }
        }
    }
    file.close();
    return occurrences;
}

int main() {
    string fileName, targetWord;

    cout << "Enter file name: ";
    getline(cin, fileName);
    cout << "Enter target word to count: ";
    getline(cin, targetWord);

    int occurrences = countWordOccurrences(fileName, targetWord);
    if (occurrences == -1)
        return 1; // Exit with error code if file opening failed

    cout << "Target word \"" << targetWord << "\" occurred " << occurrences << " times in " << fileName << "." << endl;
    return 0;
}
```
**How to use:**

1. Compile the program: `g++ word_counter.cpp -o word_counter` (assuming GCC)
2. Run the program: `./word_counter`
3. Enter the file name and target word when prompted.
4. The program will output the occurrences of the target word in the specified file.

**Notes:**

* To ignore case sensitivity, uncomment the `#include <boost/algorithm/string/case_conv.hpp>` line, add `using namespace boost;` to the using directives, and modify the comparison inside the `countWordOccurrences` function.
* This program assumes words are separated by spaces. If you need to handle punctuation or other separators, modify the `getline(lineStream, word, ' ')` line accordingly.
* Error handling is basic; you may want to add more robust error handling depending on your requirements.

Happy word counting!

Here's a Python function that utilizes dynamic programming to find the longest common subsequence (LCS) of two input strings:

```python

def longest_common_subsequence(X , Y): 
    # finding the length of the strings
    m = len(X); 
    n = len(Y); 

    # declaring the array for LCS table
    L = [[None]*(n + 1) for i in range(m + 1)]; 

    """Following steps build LCS table in bottom up fashion 
    Note: L[i][j] contains length of LCS of X[0..i-1] & Y[0..j-1]"""
    for i in range(m + 1): 
        for j in range(n + 1): 
            if i == 0 or j == 0 : 
                L[i][j] = 0
            elif X[i-1] == Y[j-1]: 
                L[i][j] = L[i-1][j-1]+1
            else: 
                L[i][j] = max(L[i-1][j], L[i][j-1]); 

    # Reconstructing the LCS
    lcs = ""; # LCS string
    i, j = m, n; 
    while i > 0 and j > 0: 

        if X[i-1] == Y[j-1]: 
            lcs = X[i-1] + lcs; 
            i -= 1; j -= 1; 

        elif L[i-1][j] > L[i][j-1]: 
            i -= 1; 

        else: 
            j -= 1; 

    return lcs

# Test the function
X = "GPavl"
Y = "GlobalPing"
print("LCS of", X, "and", Y, "is:", longest_common_subsequence(X, Y))
```

Here's how it works:

1.  Create a 2D array `L` of size `(m + 1) x (n + 1)`, where `m` and `n` are the lengths of input strings `X` and `Y`, respectively. Each cell `L[i][j]` stores the length of the longest common subsequence (LCS) of `X[0..i-1]` and `Y[0..j-1]`.
2.  Fill the `L` table in a bottom-up manner:
    *   For empty strings (`i == 0` or `j == 0`), set `L[i][j]` to 0.
    *   If the current characters in `X` and `Y` match (`X[i-1] == Y[j-1]`), increment the LCS length by 1.
    *   Otherwise, take the maximum LCS length from the top or left cell.
3.  Reconstruct the LCS string by tracing back the constructed table from bottom-right to top-left:
    *   If characters match, add the character to the LCS and move diagonally.
    *   If not, move in the direction of the larger LCS length.

The function returns the longest common subsequence as a string. In the example, the output would be `"Pal"`, which is the LCS of `"GPavl"` and `"GlobalPing"`.

